```csharp
using System;
using System.Diagnostics;
using System.Runtime.InteropServices;

class Program
{
    // Import user32.dll functions
    [DllImport("user32.dll")]
    private static extern bool SetForegroundWindow(IntPtr hWnd);

    [DllImport("user32.dll", CharSet = CharSet.Auto)]
    private static extern IntPtr FindWindow(string className, string windowName);

    [DllImport("user32.dll")]
    private static extern int SendInput(int nInputs, ref INPUT pInputs, int cbSize);

    [DllImport("user32.dll")]
    private static extern IntPtr GetMessageExtraInfo();

    private const int INPUT_KEYBOARD = 1;
    private const int VK_RETURN = 0x0D;
    private const int KEYEVENTF_EXTENDEDKEY = 0x0001;
    private const int KEYEVENTF_KEYUP = 0x0002;

    [StructLayout(LayoutKind.Sequential)]
    private struct INPUT
    {
        public int Type;
        public INPUTUNION Union;
    }

    [StructLayout(LayoutKind.Explicit)]
    private struct INPUTUNION
    {
        [FieldOffset(0)]
        public KEYBDINPUT Keyboard;
    }

    [StructLayout(LayoutKind.Sequential)]
    private struct KEYBDINPUT
    {
        public ushort Vk;
        public ushort Scan;
        public int Flags;
        public int Time;
        public IntPtr ExtraInfo;
    }

    static void Main()
    {
        string consoleWindowTitle = "YourConsoleWindowTitle";
        string commandToWrite = "YourCommand";

        // Find the console window
        IntPtr hwndConsole = FindWindow(null, consoleWindowTitle);

        if (hwndConsole != IntPtr.Zero)
        {
            // Set the console window as the foreground window
            SetForegroundWindow(hwndConsole);

            // Send each character of the command string to the console
            foreach (char c in commandToWrite)
            {
                SendKeyInput(c);
            }

            // Simulate pressing the Enter key
            SendKeyInput((char)VK_RETURN);
        }
        else
        {
            Console.WriteLine("Console window not found!");
        }

        Console.ReadLine();
    }

    private static void SendKeyInput(char character)
    {
        INPUT keyInput = new INPUT();
        keyInput.Type = INPUT_KEYBOARD;
        keyInput.Union.Keyboard.Vk = character;
        keyInput.Union.Keyboard.Scan = 0;
        keyInput.Union.Keyboard.Flags = KEYEVENTF_EXTENDEDKEY;
        keyInput.Union.Keyboard.Time = 0;
        keyInput.Union.Keyboard.ExtraInfo = GetMessageExtraInfo();

        SendInput(1, ref keyInput, Marshal.SizeOf(keyInput));

        keyInput.Union.Keyboard.Flags = KEYEVENTF_EXTENDEDKEY | KEYEVENTF_KEYUP;
        SendInput(1, ref keyInput, Marshal.SizeOf(keyInput));
    }
}
```

